#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[101];
        fgets(S, sizeof(S), stdin);
        S[strcspn(S, "\n")] = 0;
        if (strstr(S, "not") != NULL) {
            printf("Real Fancy\n");
        } else {
            printf("regularly fancy\n");
        }
    }
    return 0;
}

