using namespace std;
int main() {
    int T;
    cin >> T;
    cin.ignore();
    while (T--) {
        string S;
        getline(cin, S);
        if (S.find("not") != string::npos) {
            cout << "Real Fancy" << endl;
        } else {
            cout << "regularly fancy" << endl;
        }
    }
    return 0;
}

